  // --- TENUE DE LIVRES (BASE DE DATOS) ---
  const [historique, _setHistorique] = useState<any[]>([]);
  const reconcileHistorique = async (prev: any[], next: any[]) => {
    const userId = auth.currentUser?.uid;
    if (!userId) return;
    const deleted = prev.filter(p => !next.some(n => n.id === p.id));
    for (const item of deleted) {
      if (item.id && typeof item.id === 'string' && item.id.length > 5 && isNaN(Number(item.id))) {
        await dataService.deleteInvoiceDoc(item.id);
      }
    }
    const addedOrModified = next.filter(n => {
      const p = prev.find(x => x.id === n.id);
      if (!p) return true;
      return p.total !== n.total || p.fecha !== n.fecha || p.cliente !== n.cliente || p.cat !== n.cat || p.status !== n.status;
    });
    for (const item of addedOrModified) {
      try {
        const saved = await dataService.saveInvoice(userId, item);
        if (saved.id && saved.id !== item.id) {
          _setHistorique(current => current.map(c => c.id === item.id ? { ...c, id: saved.id } : c));
        }
      } catch (err: any) {
        console.error("Failed to save invoice:", err);
        const wasNew = !prev.some(p => p.id === item.id);
        _setHistorique(current => wasNew
          ? current.filter(c => c.id !== item.id)
          : current.map(c => c.id === item.id ? prev.find(p => p.id === item.id) : c)
        );
      }
    }
  };
  const setHistorique = (value: any[] | ((prev: any[]) => any[])) => {
    _setHistorique((prev) => {
      const next = typeof value === "function" ? value(prev) : value;
      reconcileHistorique(prev, next);
      return next;
    });
  };

  const [depenses, _setDepenses] = useState<any[]>([]);
  const reconcileExpenses = async (prev: any[], next: any[]) => {
    const userId = auth.currentUser?.uid;
    if (!userId) return;
    const deleted = prev.filter(p => !next.some(n => n.id === p.id));
    for (const item of deleted) {
      if (item.id && typeof item.id === 'string' && item.id.length > 5 && isNaN(Number(item.id))) {
        await dataService.deleteExpense(item.id);
      }
    }
    const addedOrModified = next.filter(n => {
      const p = prev.find(x => x.id === n.id);
      if (!p) return true;
      return p.total !== n.total || p.fecha !== n.fecha || p.fournisseur !== n.fournisseur || p.cat !== n.cat || p.status !== n.status || p.lien !== n.lien;
    });
    for (const item of addedOrModified) {
      try {
        const saved = await dataService.saveExpense(userId, item);
        if (saved.id && saved.id !== item.id) {
          _setDepenses(current => current.map(c => c.id === item.id ? { ...c, id: saved.id } : c));
        }
      } catch (err: any) {
        console.error("Failed to save expense:", err);
        // The item is only in local state at this point — it looked "saved" in the
        // UI but never reached Firestore. Roll it back and tell the user, instead
        // of silently losing it on the next reload.
        const wasNew = !prev.some(p => p.id === item.id);
        _setDepenses(current => wasNew
          ? current.filter(c => c.id !== item.id)
          : current.map(c => c.id === item.id ? prev.find(p => p.id === item.id) : c)
        );
        const isTrialExpiredError = err?.message === "TRIAL_EXPIRED";
        setDispatcherSuccessToast({
          text: "Erreur de sauvegarde ⚠️",
          channel: "Tenue de Livres",
          customMessage: isTrialExpiredError
            ? `Votre période d'essai est terminée — « ${item.fournisseur || item.description || "cette entrée"} » n'a pas été enregistrée. Répondez au questionnaire pour un mois gratuit additionnel : ${TRIAL_EXTENSION_FORM_URL}`
            : `« ${item.fournisseur || item.description || "Cette entrée"} » n'a pas pu être enregistrée. Vérifiez votre connexion et réessayez.`,
        });
        playErrorSound();
      }
    }
  };
  const setDepenses = (value: any[] | ((prev: any[]) => any[])) => {
    _setDepenses((prev) => {
      const next = typeof value === "function" ? value(prev) : value;
      reconcileExpenses(prev, next);
      return next;
    });
  };
