                                              { date: "2026-05-28", route: "Laval (Bureau) → Visites Clients → Montréal", motif: "Multi-destinations", distance: "42,5 km" },
                                              { date: "2026-05-25", route: "Montréal → Chantiers Flipper → Laval", motif: "Multi-destinations", distance: "28,1 km" }
